                source.node.nodeType === 1 &&
                source.node.nodeName !== 'IMAGE-WARNING'
              ) {
                source.node.setAttribute('data-qwik-cls', Number(entry.value).toFixed(3));
              }
            }
          }
          DCLS += entry.value;
        });
      });
      perfObserver.observe({ type: 'layout-shift', buffered: true });
    }
  })();
